VALUES
  ('elementary-0a2fc18c-moex-00153', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設其他條件不變。小張、小李、與小傑今天各自開車去加油，小張說：「不管油價為何，我每次都只加 10公升的油。」；小李說：「不管油價為何，我每次都只加1,000元的油。」；小傑說：「只要油價上漲， 我就不加油了！」；三人今天的汽油需求價格點彈性（絕對值）各為何？', '["小張＝0、小李＝1、小傑＝∞", "小張＝1、小李＝0、小傑＝∞", "小張＝0、小李＝∞、小傑＝1", "小張＝∞、小李＝1、小傑＝0"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00154', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '經歷缺蛋危機後，讓人憶起過去報導：「民國89年6月臺灣一斤雞蛋不到10元。當時養雞協會指出，主 要原因為兩年前蛋價超過每斤20多元，吸引大批投資者爭相投資雞蛋場所致。」報導中蛋價低迷與下列 何者有關？', '["養雞成本大幅下降", "供給人數", "禽流感導致消費者需求減少", "消費者預期變動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00155', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '有關經濟效率，下列敘述何者錯誤？', '["社會總剩餘達最大的狀態", "有外部性存在時可以達到", "市場的定價等於邊際成本", "達到巴萊圖最適的狀態"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00156', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設某商品廠商的供給線為一正斜率直線，消費者的需求線為負斜率直線。已知政府原先針對廠商課稅， 若現在改為對消費者課相同稅額，則比較改變前後廠商及消費者的租稅負擔變動，下列敘述何者正確？', '["廠商增加、消費者減少", "廠商減少、消費者增加", "廠商及消費者皆無改變", "廠商及消費者皆無法判斷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00157', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '在完全競爭市場下，下列何種情況，貨物稅將由供給者全部負擔？', '["需求完全無彈性", "供給完全有彈性", "供給完全無彈性", "需求相對於供給較無彈性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00158', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '座標平面上，X軸為牛肉，Y軸為豬肉。垂直的無異曲線說明下列何者？', '["牛肉與豬肉對此消費者而言可互相替代", "此消費者總是同時食用固定比例的牛肉與豬肉", "食用牛肉對此消費者而言味同嚼蠟、毫無樂趣", "食用豬肉對此消費者而言味同嚼蠟、毫無樂趣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00159', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設某一消費者的效用函數為U(Q)＝Qa，其中Q代表商品消費數量。a需滿足下列何種條件，方滿足邊 際效用遞減法則？', '["a＞1", "a＜-1", "0＜a＜1", "-1＜a＜0"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00160', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '一個追求效用最大的消費者決定X及Y兩種物品的最適消費量，其必須滿足的條件為何？', '["X及Y兩種物品的邊際替代率的絕對值大於兩種物品的價格比值", "X及Y兩種物品的邊際替代率的絕對值小於兩種物品的價格比值", "X及Y兩種物品的邊際替代率的絕對值等於兩種物品的價格比值", "資訊不足，無法判斷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00161', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '張三僅消費兩種產品，給定兩產品價格不變下，若張三所得減少變為原來的一半，張三的預算限制線會如 何改變？', '["斜率不變，橫軸與縱軸截距皆不變", "斜率不變，橫軸與縱軸截距皆變為原來的一半", "斜率變為原來的一半，橫軸與縱軸截距皆不變", "斜率變為原來的一半，橫軸與縱軸截距皆變為原來的一半"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00162', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設供需法則成立。在其他條件不變下，手機晶片的生產技術進步會使手機的消費者總剩餘：', '["增加", "不變", "減少", "可能增加、減少或不變"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
